import{_ as r,o as e,c as a,ac as p}from"./chunks/framework.DnBnwVZk.js";const f=JSON.parse('{"title":"Nginx 反向代理 proxy_pass 配置","description":"","frontmatter":{"title":"Nginx 反向代理 proxy_pass 配置","date":"2020-10-23T00:00:00.000Z","categories":["Linux"],"tags":["nginx","代理"],"publish":true},"headers":[],"relativePath":"views/linux/NginxProxy.md","filePath":"views/linux/NginxProxy.md","lastUpdated":1775654397000}'),o={name:"views/linux/NginxProxy.md"};function n(s,t,l,h,x,i){return e(),a("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1603411200000"},[...t[0]||(t[0]=[p('<h1 id="nginx服务器的反向代理proxy-pass配置方法讲解" tabindex="-1">Nginx服务器的反向代理proxy_pass配置方法讲解 <a class="header-anchor" href="#nginx服务器的反向代理proxy-pass配置方法讲解" aria-label="Permalink to &quot;Nginx服务器的反向代理proxy_pass配置方法讲解&quot;">​</a></h1><p>Nginx的配置还是比较简单的，如： 1 2 3 4</p><p>location ~ /* { proxy_pass <a href="http://127.0.0.1:8008" target="_blank" rel="noreferrer">http://127.0.0.1:8008</a>; }</p><p>或者可以 1 2 3 4</p><p>location / { proxy_pass <a href="http://127.0.0.1:8008" target="_blank" rel="noreferrer">http://127.0.0.1:8008</a>; }</p><p>Apache2的反向代理的配置是： 1</p><p>ProxyPass /ysz/ <a href="http://localhost:8080/" target="_blank" rel="noreferrer">http://localhost:8080/</a></p><p>然而，如果要配置一个相对复杂的反向代理 Nginx相对Apache2就要麻烦一些了 比如，将url中以/wap/开头的请求转发到后台对应的某台server上 可以再Nginx里设置一个变量，来临时保存/wap/后面的路径信息 1 2 3 4 5 6 7 8 9</p><p>location ^~ /wap/ { if ($request_uri ~ /wap/(\\d+)/(.+)) { set $bucketid $1; set $params $2; } proxy_pass <a href="http://mx:6601$bucketid.test.com/$params" target="_blank" rel="noreferrer">http://mx:6601$bucketid.test.com/$params</a>; }</p><p>也可以首先rewrite一下，然后再代理： 1 2 3 4</p><p>location ^~ /wap/{ rewrite /wap/(\\d+)/(.+) /$2?$args break; proxy_pass <a href="http://mx:6601$1.test.com" target="_blank" rel="noreferrer">http://mx:6601$1.test.com</a>; }</p><p>或者 1 2 3 4</p><p>location ~* /wap/(\\d+)/(.+) { proxy_pass <a href="http://mx:6601$1.test.com/$2?$args" target="_blank" rel="noreferrer">http://mx:6601$1.test.com/$2?$args</a>; }</p><p>注意上面最后的?$args，表明把原始url最后的get参数也给代理到后台 如果在proxy_pass中使用了变量（不管是主机名变量$1或后面的$2变量），则必须得加这段代码 但如果pass_proxy后没用任何变量，则不需要加，它默认会把所有的url都给代理到后台，如： 1 2 3 4</p><p>location ~* /wap/(\\d+)/(.+) { proxy_pass <a href="http://mx.test.com:6601" target="_blank" rel="noreferrer">http://mx.test.com:6601</a>; }</p><p>而Apache2相对就简单多了： 1 2 3 4 5 6</p><p>ProxyPassMatch ^/wap/(.*)$ <a href="http://192.168.132.147/$1" target="_blank" rel="noreferrer">http://192.168.132.147/$1</a></p><p>if ($host ~* www.(.<em>)){ set $host_without_www $1; rewrite (.</em>)$ http://$host_without_www/www$1; }</p><p>url的/问题 在nginx中配置proxy_pass时，当在后面的url加上了/，相当于是绝对根路径，则nginx不会把location中匹配的路径部分代理走;如果没有/，则会把匹配的路径部分也给代理走。</p><p>下面四种情况分别用<a href="http://192.168.1.4/proxy/test.html" target="_blank" rel="noreferrer">http://192.168.1.4/proxy/test.html</a> 进行访问。 第一种： 1 2 3</p><p>location /proxy/ { proxy_pass <a href="http://127.0.0.1:81/" target="_blank" rel="noreferrer">http://127.0.0.1:81/</a>; }</p><p>会被代理到<a href="http://127.0.0.1:81/test.html" target="_blank" rel="noreferrer">http://127.0.0.1:81/test.html</a> 这个url</p><p>第二咱(相对于第一种，最后少一个 /) 1 2 3</p><p>location /proxy/ { proxy_pass <a href="http://127.0.0.1:81" target="_blank" rel="noreferrer">http://127.0.0.1:81</a>; }</p><p>会被代理到<a href="http://127.0.0.1:81/proxy/test.html" target="_blank" rel="noreferrer">http://127.0.0.1:81/proxy/test.html</a> 这个url</p><p>第三种： 1 2 3</p><p>location /proxy/ { proxy_pass <a href="http://127.0.0.1:81/ftlynx/" target="_blank" rel="noreferrer">http://127.0.0.1:81/ftlynx/</a>; }</p><p>会被代理到<a href="http://127.0.0.1:81/ftlynx/test.html" target="_blank" rel="noreferrer">http://127.0.0.1:81/ftlynx/test.html</a> 这个url。</p><p>第四种情况(相对于第三种，最后少一个 / )： 1 2 3</p><p>location /proxy/ { proxy_pass <a href="http://127.0.0.1:81/ftlynx" target="_blank" rel="noreferrer">http://127.0.0.1:81/ftlynx</a>; }</p><p>会被代理到<a href="http://127.0.0.1:81/ftlynxtest.html" target="_blank" rel="noreferrer">http://127.0.0.1:81/ftlynxtest.html</a> 这个url</p><p>上面的结果都是本人结合日志文件测试过的。从结果可以看出，应该说分为两种情况才正确。即<a href="http://127.0.0.1:81" target="_blank" rel="noreferrer">http://127.0.0.1:81</a> (上面的第二种) 这种和 <a href="http://127.0.0.1:81/" target="_blank" rel="noreferrer">http://127.0.0.1:81/</a>.... （上面的第1，3，4种） 这种。</p><p><a href="https://www.cnblogs.com/lianxuan1768/p/8383804.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/lianxuan1768/p/8383804.html</a></p>',33)])])}const c=r(o,[["render",n]]);export{f as __pageData,c as default};
